  state.phaseStartedAt = room.phaseStartedAt;


  if (room.phase === 'submit') {
    state.submittedCardId = player?.submittedCardId || null;
  }

  if (room.phase === 'vote') {
    state.board = room.shuffledSubmissions.map(s => ({ id: s.id, card: s.card, isYours: s.playerId === playerId }));
